var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹.","JPN":"にゃあ。","ENG":"Meow.","TWN":"喵。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹, 냐옹.","JPN":"にゃあ、にゃあ。","ENG":"Meow, meow.","TWN":"喵，喵。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"왜 그래, 플루토? 그렇게 울어도 난 무슨 뜻인지 못 알아들어.","JPN":"どうしたの、プルートー？　私にはあなたの言葉がわからないよ……","ENG":"What is it, Pluto? I can't really understand what you're meowing about.","TWN":"怎麼了，布魯托？你這樣叫，我也聽不懂啊。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹, 냐옹, 냐옹!","JPN":"にゃあ、にゃあ、にゃあ！","ENG":"Meow, meow, meow!","TWN":"喵，喵，喵！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"아, 시끄러워! 이 생선 도둑아!!","JPN":"あぁ、うるさい！　このさかな泥棒！！","ENG":"Oh, hush! You stupid kitty!","TWN":"啊，吵死了！妳這個偷魚賊！！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"으아악! 책이 말을 한다!!","JPN":"うわあっ！　本がしゃべった！？","ENG":"Eeek! The book is talking!!","TWN":"額啊啊！書居然說話了！！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"왜. 책은 말하면 안 된다는 법이라도 생겼냐, 애송이 마녀야?","JPN":"何だ。本はしゃべっちゃいけないのかよ、雑魚魔女。","ENG":"What's wrong? Is it illegal for books to talk nowadays, fledgling witch?","TWN":"怎麼，有規定說書不能說話嗎？小魔女？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 아니...... 그런 법은 없긴 한데요......","JPN":"う、ううん……そんなことないよ……","ENG":"N-no... Technically it's not illegal or anything...","TWN":"不，不是……倒是沒有那種規定……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹.","JPN":"にゃあ。","ENG":"Meow.","TWN":"喵。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"거 참. 몇 번이나 말하는데 내가 하기 싫어서 계약하지 않는 게 아니라니까.","JPN":"まったく。何度も言ってるが、俺は契約を拒否してるわけではないからな。","ENG":"Oh, come on. Like I said, it's not that I don't want to sign the contract with her.","TWN":"我說過多少遍，不是我不想契約。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"이런 견습 애송이에게 함부로 책을 열어 줬다간 몸이 타 버린다고!","JPN":"こんな見習いにむやみに本を開けられたら、体が燃えちまう！","ENG":"If I open myself up to a fledgling like this, I'd burn her all up!","TWN":"主要是不能隨意讓這種見習小屁孩打開書啊，會被燒死的！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹, 냐옹.","JPN":"にゃあ、にゃあ。","ENG":"Meow, meow.","TWN":"喵，喵。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"뭐? 얘가 메이 녀석 손녀라고?","JPN":"何だと？　この子がメイの孫？","ENG":"What? She's May's granddaughter?","TWN":"什麼？她是梅伊那傢伙的孫女？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"하! 그 꼬맹이가 벌써 손녀까지 봤다니 시간이 참 빠르기도 하군.","JPN":"は！　あのチビに孫までいるとは、時間が経つのは早いものだ。","ENG":"Hah! That little lass already had a grandchild? My, time sure flies, doesn't it?","TWN":"哈！那個小不點居然已經有孫女了，時間過得真快。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"아니지. 그동안 날 이런 데 혼자 처박아 뒀다고 화내야 하나?","JPN":"いや、今までこんなところに俺をほったらかしてたんだから怒るべきか？","ENG":"Or wait. Maybe I should be cross that she left me cooped up for so long?","TWN":"不，居然把我放置這麼久，我是不是該生氣？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹, 냐옹, 냐옹.","JPN":"にゃあ、にゃあ、にゃあ。","ENG":"Meow, meow, meow.","TWN":"喵，喵，喵。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"그래도 안 되는 건 안 돼! 정 필요하면 메이 더러 직접 오라고 해!","JPN":"それでもダメなものはダメだ！　どうしても\\n必要ならメイに直接来るように伝えてくれ！","ENG":"I told you that's not a good idea! If it's really necessary, just tell May to come herself!","TWN":"即使如此也不行！如果需要的話，那就讓梅伊親自過來吧！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"왜 자꾸 억지를 쓰는 거냐, 귀찮은 네발 짐승 녀석아.","JPN":"しつこいな、面倒くさい四足獣め。","ENG":"Stop being so stubborn, you pesky little feline.","TWN":"你怎麼耍賴呢，煩人的四腳禽獸。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹......","JPN":"にゃあ……","ENG":"Meow...","TWN":"喵……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOLA_CODEX_NULL_NULL","text":{"KOREA":"뭐? 메이가 죽었다고......?","JPN":"何だと？　メイが死んだ……？","ENG":"What? May is dead?","TWN":"什麼？梅伊死了……？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};